// Timezone shift makes cached records appear "from the future"

val cachedRecords = db.query(
    "SELECT * FROM events WHERE time <= ?",
    arrayOf(System.currentTimeMillis().toString())
)

val latest = cachedRecords.last()  // 💥 CRASH: empty list if all records
                                    // are now "in the future"
```

```swift
