    def _build_field_mappings(self, config: IndexConfig) -> Dict:
        """Build field mappings based on tier"""
        base_mappings = {
            "id": {"type": "keyword"},
            "date": {"type": "date", "format": "yyyy-MM-dd||epoch_millis"},
            "title": {
                "type": "text",
                "analyzer": "custom_analyzer",
                "fields": {
                    "keyword": {"type": "keyword", "ignore_above": 256},
                    "suggest": {"type": "completion"}  # Autocomplete support
                }
            },
            "category": {"type": "keyword"},
            "tags": {"type": "keyword"},
        }

        # Only add expensive fields for hot tier
        if config.tier == DataTier.HOT:
            base_mappings.update({
                "content": {
                    "type": "text",
                    "analyzer": "custom_analyzer",
                    "term_vector": "with_positions_offsets",  # For highlighting
                    "store": False  # Don't store separately - saves space
