                "metadata": {
                    "type": "object",
                    "enabled": True
                },
                "vector_embedding": {
                    "type": "dense_vector",
                    "dims": 384,        # For semantic search
                    "index": True,
                    "similarity": "cosine"
                }
            })

        return base_mappings
